package com.clashcoach.player;
import com.fasterxml.jackson.databind.JsonNode; import java.util.*; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.*; import org.springframework.stereotype.Component; import org.springframework.web.client.*;
/** Adapter for the official read-only Clash of Clans player API. */
@Component public class ClashApiClient { private final RestTemplate client; private final String baseUrl,token; public ClashApiClient(RestTemplateBuilderFactory factory,@Value("${app.clash.base-url}") String baseUrl,@Value("${app.clash.api-token}") String token){this.client=factory.create();this.baseUrl=baseUrl;this.token=token;} public PlayerData getPlayer(String tag){if(token==null||token.trim().isEmpty())throw new ProviderUnavailableException("Clash API token is not configured");try{HttpHeaders headers=new HttpHeaders();headers.setBearerAuth(token);JsonNode node=client.exchange(baseUrl+"/players/{tag}",HttpMethod.GET,new HttpEntity<Void>(headers),JsonNode.class,tag).getBody();if(node==null)throw new ProviderUnavailableException("Clash API returned no data");List<PlayerData.Hero> heroes=new ArrayList<PlayerData.Hero>();for(JsonNode hero:node.path("heroes"))heroes.add(new PlayerData.Hero(hero.path("name").asText(),hero.path("level").asInt()));return new PlayerData(node.path("name").asText(),node.path("townHallLevel").asInt(),node.path("expLevel").asInt(),node.path("trophies").asInt(),heroes);}catch(HttpClientErrorException.NotFound exception){throw new PlayerNotFoundException();}catch(RestClientException exception){throw new ProviderUnavailableException("Clash API is unavailable");}} public static class PlayerNotFoundException extends RuntimeException{} public static class ProviderUnavailableException extends RuntimeException{public ProviderUnavailableException(String message){super(message);}} }
